const Sentry = require('@sentry/node');

// Inicjalizuj Sentry (raz na workflow)
Sentry.init({
  dsn: 'https://65d16a394a93442fb661943d33474b60@glitchtip.trustcode.pl/1',
  environment: 'production',
  tracesSampleRate: 1.0,
  sendDefaultPii: true,
  enableLogs: true
});

// Extract error data - POPRAWIONA STRUKTURA
const errorData = $input.all()[0]?.json;
const execution = errorData?.execution;
const workflow = errorData?.workflow;
const error = execution?.error;
const executionContext = execution?.executionContext;

console.log('Raw input:', JSON.stringify($input.all(), null, 2));

// Set up context
Sentry.setUser({
  id: executionContext?.source || 'system',
  username: executionContext?.source,
});

// Add comprehensive tags
Sentry.setTag('workflow_id', workflow?.id);
Sentry.setTag('workflow_name', workflow?.name);
Sentry.setTag('execution_id', execution?.id);
Sentry.setTag('execution_mode', execution?.mode);
Sentry.setTag('last_node', execution?.lastNodeExecuted);
Sentry.setTag('trigger_type', executionContext?.triggerNode?.type);
Sentry.setTag('error_line', error?.lineNumber);

// Set context for more details
Sentry.setContext('workflow', {
  id: workflow?.id,
  name: workflow?.name,
});

Sentry.setContext('execution', {
  id: execution?.id,
  url: execution?.url,
  mode: execution?.mode,
  lastNodeExecuted: execution?.lastNodeExecuted,
  establishedAt: executionContext?.establishedAt,
});

Sentry.setContext('trigger', {
  source: executionContext?.source,
  nodeName: executionContext?.triggerNode?.name,
  nodeType: executionContext?.triggerNode?.type,
});

// Add breadcrumbs - execution flow
Sentry.addBreadcrumb({
  category: 'workflow',
  message: `Workflow "${workflow?.name}" started`,
  level: 'info',
  data: {
    workflow_id: workflow?.id,
    trigger: executionContext?.triggerNode?.name,
  },
});

Sentry.addBreadcrumb({
  category: 'execution',
  message: `Failed at node: ${execution?.lastNodeExecuted}`,
  level: 'error',
  data: {
    execution_id: execution?.id,
    execution_url: execution?.url,
    line_number: error?.lineNumber,
  },
});

// Create descriptive error message
const errorMessage = `[${workflow?.name}] ${error?.message || 'Unknown error'} at node "${execution?.lastNodeExecuted}"`;

// Capture the exception with full context
Sentry.captureException(new Error(errorMessage), {
  level: error?.level || 'error',
  extra: {
    // Error details
    error_name: error?.name,
    error_description: error?.description,
    error_line: error?.lineNumber,
    full_stack: error?.stack,

    // Execution details
    execution_id: execution?.id,
    execution_url: execution?.url,
    execution_mode: execution?.mode,
    last_node_executed: execution?.lastNodeExecuted,

    // Workflow context
    workflow_id: workflow?.id,
    workflow_name: workflow?.name,

    // Trigger context
    trigger_source: executionContext?.source,
    trigger_node: executionContext?.triggerNode?.name,
    trigger_type: executionContext?.triggerNode?.type,
    established_at: executionContext?.establishedAt,

    // Raw data for debugging
    raw_error_data: errorData,
  },
  fingerprint: [
    workflow?.id,
    execution?.lastNodeExecuted,
    error?.message?.split('[')[0]?.trim(), // Group similar errors together
  ],
});

// WAŻNE: Flush zapewnia że event zostanie wysłany przed zakończeniem funkcji
await Sentry.flush(2000);

return {
  success: true,
  message: 'Error tracked in GlitchTip',
  sentry_context: {
    workflow: workflow?.name,
    node: execution?.lastNodeExecuted,
    execution_url: execution?.url,
    error_message: errorMessage,
  },
};
